solution_code:
#include <iostream>

int main() {
    char letter;
    int offset;
    std::cin >> letter >> offset;

    int result = letter + offset;   // char promoted to int before addition
    char shifted = static_cast<char>(result);

    std::cout << letter << " + " << offset << " = " << shifted << "\n";
    return 0;
}

