#include <iostream>

int countTrueValues(bool a, bool b, bool c) {
    return a + b + c;  // each bool promotes to int (true->1, false->0)
}

int main() {
    int x, y, z;
    std::cin >> x >> y >> z;

    bool a = x;
    bool b = y;
    bool c = z;

    int count = countTrueValues(a, b, c);
    std::cout << "True count: " << count << "\n";
    return 0;
}
